easy.solution:
def check_pos(n):
    if n <= 0: raise ValueError('Must be positive')
    return n

medium.solution:
def concat(s1, s2):
    if not isinstance(s1, str) or not isinstance(s2, str):
        raise TypeError('Both arguments must be strings')
    return s1 + s2

hard.solution:
def get_req(d, k):
    try: return d[k]
    except KeyError as e: raise RuntimeError(f'Missing key {k}') from e
